from collections import deque

n = int(input())
a = list(map(int, input().split()))
b = list(map(int, input().split()))

INF = float('inf')
dist = [INF] * (n + 1)
dist[n] = 0
q = deque([n])

while q:
    x = q.popleft()
    if x == 0:
        break
    for dx in range(1, a[x - 1] + 1):
        y = x - dx
        if y < 0:
            continue
        y_after_slip = y + b[y]
        if y_after_slip > n:
            continue
        if dist[y_after_slip] > dist[x] + 1:
            dist[y_after_slip] = dist[x] + 1
            q.append(y_after_slip)

if dist[0] == INF:
    print(-1)
else:
    print(dist[0])
    path = []
    x = 0
    while x != n:
        for dx in range(1, a[x + b[x] - 1] + 1):
            y = x + dx
            if y > n:
                continue
            if dist[x] == dist[y] + 1:
                path.append(x)
                x = y
                break
    path.append(n)
    path.reverse()
    print(' '.join(map(str, path[:-1])))
